const {
  Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell,
  WidthType, ShadingType, BorderStyle, AlignmentType, PageBreak
} = require("docx");

const ACCENT = "1E293B";
const BLUE = "2563EB";
const LIGHT = "F8FAFC";

function h1(text) {
  return new Paragraph({ text, heading: HeadingLevel.HEADING_1, spacing: { before: 400, after: 200 } });
}
function h2(text, color) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 300, after: 120 },
    children: [new TextRun({ text, bold: true, color: color || BLUE })]
  });
}
function body(text) {
  return new Paragraph({ text, spacing: { after: 160 }, alignment: AlignmentType.LEFT });
}
function bullet(text) {
  return new Paragraph({ text, bullet: { level: 0 }, spacing: { after: 80 } });
}
function qa(q, a) {
  return [
    new Paragraph({ spacing: { before: 120, after: 40 }, children: [new TextRun({ text: "Q: ", bold: true, color: BLUE }), new TextRun({ text: q, bold: true })] }),
    new Paragraph({ spacing: { after: 120 }, children: [new TextRun({ text: "A: ", bold: true }), new TextRun({ text: a })] })
  ];
}
function divider() {
  return new Paragraph({ text: "", border: { bottom: { color: "CBD5E1", space: 4, style: BorderStyle.SINGLE, size: 6 } }, spacing: { after: 300 } });
}

